document.addEventListener('DOMContentLoaded',function(){const carousels=document.querySelectorAll('.carousel');carousels.forEach(function(carousel){const slides=carousel.querySelectorAll('.carousel-slide');const prevBtn=carousel.querySelector('.carousel-prev');const nextBtn=carousel.querySelector('.carousel-next');const dotsContainer=carousel.querySelector('.carousel-dots');const interval=parseInt(carousel.getAttribute('data-interval'))|| 4000;if(slides.length<=1){if(prevBtn)prevBtn.style.display='none';if(nextBtn)nextBtn.style.display='none';if(dotsContainer)dotsContainer.style.display='none';return;}let currentIndex=0;let autoPlayTimer=null;function createDots(){if(!dotsContainer)return;dotsContainer.innerHTML='';slides.forEach(function(_,index){const dot=document.createElement('button');dot.classList.add('dot');dot.setAttribute('aria-label','Ir para imagem '+(index+1));if(index===0)dot.classList.add('active');dot.addEventListener('click',function(){goToSlide(index);resetAutoPlay();});dotsContainer.appendChild(dot);});}function goToSlide(index){slides.forEach(function(slide,i){slide.classList.toggle('active',i===index);});if(dotsContainer){const dots=dotsContainer.querySelectorAll('.dot');dots.forEach(function(dot,i){dot.classList.toggle('active',i===index);});}currentIndex=index;}function nextSlide(){const next=(currentIndex+1)% slides.length;goToSlide(next);}function prevSlide(){const prev=(currentIndex-1+slides.length)% slides.length;goToSlide(prev);}function startAutoPlay(){stopAutoPlay();autoPlayTimer=setInterval(nextSlide,interval);}function stopAutoPlay(){if(autoPlayTimer){clearInterval(autoPlayTimer);autoPlayTimer=null;}}function resetAutoPlay(){startAutoPlay();}if(prevBtn){prevBtn.addEventListener('click',function(e){e.stopPropagation();prevSlide();resetAutoPlay();});}if(nextBtn){nextBtn.addEventListener('click',function(e){e.stopPropagation();nextSlide();resetAutoPlay();});}carousel.addEventListener('mouseenter',stopAutoPlay);carousel.addEventListener('mouseleave',startAutoPlay);createDots();startAutoPlay();let touchStartX=0;let touchEndX=0;carousel.addEventListener('touchstart',function(e){touchStartX=e.changedTouches[0].screenX;},{passive:true});carousel.addEventListener('touchend',function(e){touchEndX=e.changedTouches[0].screenX;handleSwipe();},{passive:true});function handleSwipe(){const swipeThreshold=50;const diff=touchStartX-touchEndX;if(Math.abs(diff)>swipeThreshold){if(diff>0){nextSlide();}else{prevSlide();}resetAutoPlay();}}});});